CREATE TABLE IF NOT EXISTS spectrem_director_users (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, identifier VARCHAR(64) NOT NULL UNIQUE, role VARCHAR(20) NOT NULL DEFAULT 'user', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS spectrem_director_projects (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, owner_identifier VARCHAR(64) NOT NULL, name VARCHAR(80) NOT NULL, payload LONGTEXT NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, INDEX(owner_identifier));
CREATE TABLE IF NOT EXISTS spectrem_director_scenes (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, project_id BIGINT UNSIGNED NOT NULL, data JSON NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, INDEX(project_id));
CREATE TABLE IF NOT EXISTS spectrem_director_entities (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, project_id BIGINT UNSIGNED NOT NULL, entity_type VARCHAR(16) NOT NULL, data JSON NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, INDEX(project_id));
CREATE TABLE IF NOT EXISTS spectrem_director_favorites (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, owner_identifier VARCHAR(64) NOT NULL, favorite_type VARCHAR(24) NOT NULL, favorite_key VARCHAR(128) NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, UNIQUE KEY favorite(owner_identifier,favorite_type,favorite_key));
CREATE TABLE IF NOT EXISTS spectrem_director_camera_presets (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, owner_identifier VARCHAR(64) NOT NULL, name VARCHAR(80) NOT NULL, data JSON NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS spectrem_director_weather_presets (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, owner_identifier VARCHAR(64) NOT NULL, name VARCHAR(80) NOT NULL, data JSON NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS spectrem_director_logs (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, level VARCHAR(16) NOT NULL, message TEXT NOT NULL, context JSON NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, INDEX(level,created_at));
CREATE TABLE IF NOT EXISTS spectrem_director_actors (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, project_id BIGINT UNSIGNED NOT NULL, name VARCHAR(80) NOT NULL, model VARCHAR(128) NOT NULL, data JSON NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, INDEX(project_id));
CREATE TABLE IF NOT EXISTS spectrem_director_props (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, project_id BIGINT UNSIGNED NOT NULL, name VARCHAR(80) NOT NULL, model VARCHAR(128) NOT NULL, data JSON NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, INDEX(project_id));
CREATE TABLE IF NOT EXISTS spectrem_director_vehicles (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, project_id BIGINT UNSIGNED NOT NULL, name VARCHAR(80) NOT NULL, model VARCHAR(128) NOT NULL, data JSON NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, INDEX(project_id));
CREATE TABLE IF NOT EXISTS spectrem_director_animations (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, owner_identifier VARCHAR(64) NOT NULL, label VARCHAR(80) NOT NULL, dictionary VARCHAR(128) NOT NULL, clip VARCHAR(128) NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS spectrem_director_settings (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, owner_identifier VARCHAR(64) NOT NULL UNIQUE, data JSON NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS spectrem_director_permissions (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, identifier VARCHAR(64) NOT NULL UNIQUE, role VARCHAR(20) NOT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP);
